@Component
public class MyBatchStep implements Step {

    @Autowired
    private MyItemReader itemReader;

    @Autowired
    private MyItemProcessor itemProcessor;

    @Autowired
    private MyItemWriter itemWriter;

    @Value("${batch.chunkSize}")
    private int chunkSize;

    @Override
    public void execute(StepExecution stepExecution) throws JobInterruptedException {
        StepContext stepContext = stepExecution.getExecutionContext();
        int processedCount = stepContext.getInt("processedCount", 0);

        try {
            itemReader.open(stepExecution.getExecutionContext());
            itemWriter.open(stepExecution.getExecutionContext());

            while (true) {
                List<MyInput> items = itemReader.read(chunkSize);

                if (items == null || items.isEmpty()) {
                    break;
                }

                List<MyOutput> outputs = new ArrayList<>(items.size());

                for (MyInput input : items) {
                    MyOutput output = itemProcessor.process(input);
                    outputs.add(output);
                }

                itemWriter.write(outputs);

                processedCount += items.size();
                stepContext.putInt("processedCount", processedCount);
            }
        } catch (Exception e) {
            throw new RuntimeException("Failed to process batch", e);
        } finally {
            itemReader.close();
            itemWriter.close();
