## ✅ Step 1: Create the Shader

Create a new shader called `DepthOfFieldGaussianShader` in Unity, and paste the following code:

```csharp
Shader "Custom/DepthOfFieldGaussian"
{
    Properties
    {
        _MainTex ("Texture", 2D) = "white" {}
        _CameraDepthTexture ("Camera Depth Texture", 2D) = "white" {}
        _FocusDistance ("Focus Distance", Float) = 5.0
        _FalloffDistance ("Falloff Distance", Float) = 10.0
        _BlurRadius ("Blur Radius", Float) = 3.0
        _BlurAmount ("Blur Amount", Float) = 1.0
    }

    SubShader
    {
        Tags { "RenderType"="Opaque" "Queue"="Geometry" }
        LOD 200

        Pass
        {
            Name "GaussianBlur"
            ZWrite Off
            ZTest Off
            Cull Off
            Blend SrcAlpha OneMinusSrcAlpha
            Lighting Off
            Fog { Mode Off }

            CGPROGRAM
            #pragma target 3.0
            #pragma vertex vert
            #pragma fragment frag
            #include "UnityCG.cginc"

            sampler2D _MainTex;
            sampler2D _CameraDepthTexture;
            float _FocusDistance;
            float _FalloffDistance;
            float _BlurRadius;
            float _BlurAmount;

            struct appdata
            {
                float4 vertex : POSITION;
                float2 uv : TEXCOORD0;
            };

            struct v2f
            {
                float2 uv : TEXCOORD0;
                float4 pos : SV_POSITION;
            };

            v2f vert(appdata v)
            {
                v2f o;
                o.pos = UnityObjectToClipPos(v.vertex);
                o.uv = v.uv;
                return o;
            }

            float4 frag(v2f i) : SV_Target
            {
                float2 screenUV = i.uv;
                float depth = tex2D(_CameraDepthTexture, screenUV).r;

                // Calculate distance from focus
                float distanceFromFocus = abs(depth - _FocusDistance);
                float blurFactor = saturate(distanceFromFocus / _FalloffDistance);

                // Apply blur based on blurFactor
                float blur = _BlurRadius * blurFactor;
                float blurAmount = _BlurAmount * blur;

                // Simple Gaussian blur (in screen space)
                // This is a very basic approximation for clarity
                float2 offset = float2(0, 0);
                float blurValue = 0.0;

                for (int i = 0; i < 5; i++)
                {
                    offset = float2(0, i - 2) * blurAmount;
                    float sample = tex2D(_MainTex, screenUV + offset).r;
                    blurValue += sample;
                }

                return float4(blurValue / 5.0, 0, 0, 1);
            }
            ENDCG
        }
    }
}
```

> ✅ This is a **very basic** Gaussian blur in screen space. You can expand this with **more sophisticated blur kernels** (e.g., using a blur kernel with a Gaussian distribution) or **multi-pass blurring** for better performance.

