### 1. Update the `OrthographicDepthOfFieldPass` constructor

Change the constructor to pass the correct shader and pass index:

```csharp
public class OrthographicDepthOfFieldPass : ScriptableRenderPass
{
    private Material _material;
    private string _profilerTag;
    private RenderTargetIdentifier _source;
    private RenderTargetHandle _destination;
    private OrthographicDepthOfFieldFeature.BlurAlgorithm _blurAlgorithm;

    public OrthographicDepthOfFieldPass(string profilerTag, Shader shader, OrthographicDepthOfFieldFeature.BlurAlgorithm blurAlgorithm)
    {
        _profilerTag = profilerTag;
        _material = new Material(shader);
        _blurAlgorithm = blurAlgorithm;
    }

    public void Setup(RenderTargetIdentifier source, RenderTargetHandle destination)
    {
        _source = source;
        _destination = destination;
    }

    public override void Execute(ScriptableRenderContext context, ref RenderingData renderingData)
    {
        CommandBuffer cmd = CommandBufferPool.Get(_profilerTag);

        // Set the material to the correct pass (Gaussian blur pass)
        int shaderPassIndex = 0;

        // Set global properties
        cmd.SetGlobalTexture("_CameraDepthTexture", renderingData.cameraData.renderer.GetCameraDepth(_source));
        cmd.SetGlobalFloat("_FocusDistance", OrthographicDepthOfFieldFeature.FocusDistance);
        cmd.SetGlobalFloat("_FalloffDistance", OrthographicDepthOfFieldFeature.FalloffDistance);
        cmd.SetGlobalFloat("_BlurRadius", OrthographicDepthOfFieldFeature.BlurRadius);
        cmd.SetGlobalFloat("_BlurAmount", OrthographicDepthOfFieldFeature.BlurAmount);

        // Blit the source to the destination with the material
        cmd.Blit(_source, _destination.Identifier(), _material, shaderPassIndex);

        // Blit the destination back to the source (since we're using a render texture)
        cmd.Blit(_destination.Identifier(), _source);

        context.ExecuteCommandBuffer(cmd);
        cmd.Clear();

        CommandBufferPool.Release(cmd);
    }
}
```

> ✅ This script now uses the `DepthOfFieldGaussianShader` and applies the **Gaussian blur** pass.

