## ✅ Step 3: Update the Feature Script

Now, make sure your `OrthographicDepthOfFieldFeature` script includes the `BlurAlgorithm` enum and references the shader.

```csharp
public class OrthographicDepthOfFieldFeature : ScriptableRendererFeature
{
    public enum BlurAlgorithm
    {
        GaussianBlur,
        BilateralFilter,
        BokehBlur
    }

    [Header("Blur Settings")]
    public BlurAlgorithm blurAlgorithm = BlurAlgorithm.GaussianBlur;
    public Shader depthOfFieldShader;

    [Header("Depth of Field Parameters")]
    public static float FocusDistance = 5f;
    public static float FalloffDistance = 10f;
    public static float BlurRadius = 3f;
    public static float BlurAmount = 1.0f;

    private OrthographicDepthOfFieldPass _scriptablePass;

    public override void Create()
    {
        if (depthOfFieldShader == null)
        {
            Debug.LogError("Depth of Field shader is missing! Assign it in the OrthographicDepthOfFieldFeature.");
            return;
        }

        _scriptablePass = new OrthographicDepthOfFieldPass("OrthographicDepthOfField", depthOfFieldShader, blurAlgorithm);
    }

    public override void AddRenderPass(CommandBuffer cmd, ref RenderingData renderingData)
    {
        _scriptablePass.Setup(_source, _destination);
        _scriptablePass.Execute(cmd, ref renderingData);
    }
}
```

