defined('BASEPATH') OR exit('No direct script access allowed');

class Template_model extends CI_Model {

    public function get_all_templates() {
        $query = $this->db->get('templates');
        return $query->result_array();
    }

    public function save_template($data) {
        return $this->db->insert('templates', $data);
    }

    public function get_template_by_id($id) {
        $query = $this->db->get_where('templates', ['id' => $id]);
        return $query->row_array();
    }

    public function generate_json($data) {
        $json_file = FCPATH . 'uploads/templates/' . $data['name'] . '.json';
        file_put_contents($json_file, json_encode($data, JSON_PRETTY_PRINT));
    }

    public function generate_csv($data) {
        $csv_file = FCPATH . 'uploads/templates/' . $data['name'] . '.csv';
        $fp = fopen($csv_file, 'w');

        // CSV headers
        fputcsv($fp, ['name', 'duration', 'thumbnail', 'preview_url', 'assets']);

        // CSV data
        fputcsv($fp, [
            $data['name'],
            $data['duration'],
            $data['thumbnail'],
            $data['preview_url'],
            $data['assets']
        ]);

        fclose($fp);
    }
}
